    <style>
        /* Custom animation logic will still be handled with JavaScript */
        .moving-div {
            position: fixed;
            transform: translateX(0);
            /* Default transform */
            transition: transform 0.3s;
            /* Smooth transition */
        }
    </style>


    <script>
        const movingDiv = document.querySelector('.moving-div');
        let direction = 1; // 1 = moving right, -1 = moving left
        let currentOffset = 0; // Current offset in pixels
        const maxOffset = 200; // Maximum movement in pixels
        const step = 2; // Number of pixels to move in each step
        const interval = 300; // Time in milliseconds between steps

        function moveDiv() {
            // Update the offset
            currentOffset += step * direction;

            // Reverse direction if limits are reached
            if (currentOffset >= maxOffset || currentOffset <= 0) {
                direction *= -1;
            }

            // Update the position of the div
            movingDiv.style.transform = `translateX(${-currentOffset}px)`;
        }

        // function moveDiv() {
